final class CanvasAnimationView: UIView {
    private var fps: Int?
    private var frames: [AnimationFrame]?
    private var displayLink: CADisplayLink?
    private var startTime: CFTimeInterval?
    override func draw(_ rect: CGRect) {
        super.draw(rect)
        guard
            let fps, let frames, let startTime,
            let context = UIGraphicsGetCurrentContext()
        else {
            return
        }
        let currentTime = CACurrentMediaTime()
        let currentFrame = Int((currentTime - startTime) * Double(fps)) % frames.count
        for i in 0 ..< frames[currentFrame].strokesMaxIndex {
            frames[currentFrame].strokes[i].draw(inContext: context)
        }
    }
    init() {
        super.init(frame: .zero)
        backgroundColor = .clear
    }
    @available(*, unavailable)
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    func startAnimation(frames: [AnimationFrame], fps: Int) {
        self.frames = frames
        self.fps = fps
        displayLink = .init(target: self, selector: #selector(displayLinkDidFire(_:)))
        startTime = CACurrentMediaTime()
        displayLink?.add(to: .main, forMode: .common)
    }
    func endAnimation() {
        displayLink?.isPaused = true
        displayLink?.invalidate()
        fps = nil
        frames = nil
        displayLink = nil
        startTime = nil
    }
    @objc
    private func displayLinkDidFire(_ sender: CADisplayLink) {
        setNeedsDisplay()
    }
}

final class CanvasView: UIView {
    weak var delegate: CanvasViewDelegate?
    var currentTool: (any DrawingTool)? {
        didSet {
            currentTool?.delegate = self
        }
    }
    private(set) var isUndoEnabled: Bool {
        didSet {
            if oldValue != isUndoEnabled {
                delegate?.canvasView(self, updateIsUndoEnabled: isUndoEnabled)
            }
        }
    }
    private(set) var isRedoEnabled: Bool {
        didSet {
            if oldValue != isRedoEnabled {
                delegate?.canvasView(self, updateIsRedoEnabled: isRedoEnabled)
            }
        }
    }
    private var strokesMaxIndex = 0
    private var strokes: [DrawingToolStroke] = []
    private var underlyingStrokesMaxIndex: Int?
    private var underlyingStrokes: [DrawingToolStroke]?
    init() {
        isUndoEnabled = false
        isRedoEnabled = false
        super.init(frame: .zero)
        backgroundColor = .clear
        setupGestures()
    }
    @available(*, unavailable)
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    override func draw(_ rect: CGRect) {
        super.draw(rect)
        guard let context = UIGraphicsGetCurrentContext() else { return }
        if let underlyingStrokes, let underlyingStrokesMaxIndex {
            context.setAlpha(0.3)
            for i in 0 ..< underlyingStrokesMaxIndex {
                underlyingStrokes[i].draw(inContext: context)
            }
            context.setAlpha(1)
        }
        for i in 0 ..< strokesMaxIndex {
            strokes[i].draw(inContext: context)
        }
        currentTool?.drawCurrentStroke(inContext: context)
    }
    func undo() {
        guard strokesMaxIndex > 0 else { return }
        strokesMaxIndex -= 1
        updateUndoAndRedoStates()
        setNeedsDisplay()
        delegate?.canvasView(self, didAlterFrame: getFrame())
    }
    func redo() {
        guard strokesMaxIndex < strokes.count else { return }
        strokesMaxIndex += 1
        updateUndoAndRedoStates()
        setNeedsDisplay()
        delegate?.canvasView(self, didAlterFrame: getFrame())
    }
    func getFrame() -> AnimationFrame {
        .init(
            size: frame.size,
            strokesMaxIndex: strokesMaxIndex,
            strokes: strokes
        )
    }
    func setFrame(_ frame: AnimationFrame, underlyingFrame: AnimationFrame?) {
        strokesMaxIndex = frame.strokesMaxIndex
        strokes = frame.strokes
        underlyingStrokesMaxIndex = underlyingFrame?.strokesMaxIndex
        underlyingStrokes = underlyingFrame?.strokes
        updateUndoAndRedoStates()
        setNeedsDisplay()
    }
    private func setupGestures() {
        let panGestureRecognizer = UIPanGestureRecognizer(target: self, action: #selector(onPanGestureRecognized(_:)))
        addGestureRecognizer(panGestureRecognizer)
    }
    @objc
    private func onPanGestureRecognized(_ sender: UIPanGestureRecognizer) {
        let point = sender.location(in: self)
        switch sender.state {
        case .began:
            delegate?.canvasViewStartedEditing(self)
            currentTool?.startedPan(atPoint: point)
        case .changed:
            currentTool?.continuedPan(atPoint: point)
        case .ended:
            currentTool?.finishedPan(atPoint: point)
        default:
            break
        }
    }
    private func updateUndoAndRedoStates() {
        isUndoEnabled = strokesMaxIndex > 0
        isRedoEnabled = strokesMaxIndex < strokes.count
    }
}

final class EllipseDrawingTool: DrawingTool {
    typealias Stroke = EllipseStroke
    static func drawStroke(_ stroke: EllipseStroke, inContext context: CGContext) {
        context.setBlendMode(.copy)
        context.setStrokeColor(stroke.strokeColor.cgColor)
        context.setLineWidth(stroke.strokeWidth)
        context.strokeEllipse(in: .init(from: stroke.startPoint, to: stroke.endPoint))
    }
    var delegate: DrawingToolDelegate?
    let strokeColor: UIColor
    let strokeWidth: CGFloat
    var startPoint: CGPoint?
    var endPoint: CGPoint?
    init(strokeColor: UIColor, strokeWidth: CGFloat) {
        self.strokeColor = strokeColor
        self.strokeWidth = strokeWidth
    }
    func startedPan(atPoint point: CGPoint) {
        startPoint = point
    }
    func continuedPan(atPoint point: CGPoint) {
        guard let startPoint else { return }
        endPoint = point
        delegate?.drawingToolSetNeedsDisplay(self)
    }
    func finishedPan(atPoint point: CGPoint) {
        guard let startPoint else { return }
        let stroke = Stroke(
            strokeColor: strokeColor,
            strokeWidth: strokeWidth,
            startPoint: startPoint,
            endPoint: point
        )
        self.startPoint = nil
        self.endPoint = nil
        delegate?.drawingTool(self, didCreateStroke: stroke)
    }
    func drawCurrentStroke(inContext context: CGContext) {
        guard let startPoint, let endPoint else { return }
        context.setBlendMode(.copy)
        context.setStrokeColor(strokeColor.cgColor)
        context.setLineWidth(strokeWidth)
        context.strokeEllipse(in: .init(from: startPoint, to: endPoint))
    }
}

final class EraserDrawingTool: DrawingTool {
    typealias Stroke = EraserStroke
    static func drawStroke(_ stroke: EraserStroke, inContext context: CGContext) {
        context.setBlendMode(.copy)
        context.setStrokeColor(UIColor.clear.cgColor)
        context.setLineWidth(stroke.strokeWidth)
        for (index, point) in stroke.points.enumerated() {
            switch index {
            case 0:
                context.move(to: point)
            default:
                context.addLine(to: point)
            }
        }
        context.strokePath()
    }
    var delegate: DrawingToolDelegate?
    let strokeWidth: CGFloat
    var currentStrokePoints: [CGPoint] = []
    init(strokeWidth: CGFloat) {
        self.strokeWidth = strokeWidth
    }
    func startedPan(atPoint point: CGPoint) {
        currentStrokePoints = [point]
    }
    func continuedPan(atPoint point: CGPoint) {
        currentStrokePoints.append(point)
        delegate?.drawingToolSetNeedsDisplay(self)
    }
    func finishedPan(atPoint point: CGPoint) {
        currentStrokePoints.append(point)
        guard currentStrokePoints.count > 1 else { return }
        let strokeInfo = Stroke(
            strokeWidth: strokeWidth,
            points: currentStrokePoints
        )
        currentStrokePoints = []
        delegate?.drawingTool(self, didCreateStroke: strokeInfo)
        delegate?.drawingToolSetNeedsDisplay(self)
    }
    func drawCurrentStroke(inContext context: CGContext) {
        guard currentStrokePoints.count > 1 else { return }
        context.setBlendMode(.copy)
        context.setStrokeColor(UIColor.clear.cgColor)
        context.setLineWidth(strokeWidth)
        for (index, point) in currentStrokePoints.enumerated() {
            switch index {
            case 0:
                context.move(to: point)
            default:
                context.addLine(to: point)
            }
        }
        context.strokePath()
    }
}

